def _env_flag(name: str, default: bool = False) -> bool:
    """
    Parse env flag: 1/true/yes/on => True; 0/false/no/off => False
    """
    v = os.getenv(name)
    if v is None:
        return default
    v = str(v).strip().lower()
    return v in ("1", "true", "yes", "y", "on")

def _profile_flag(profile: dict, key: str):
    """
    Read boolean-ish toggle from request profile, if exists.
    Accepts: True/False, 1/0, "true"/"false", "on"/"off".
    Returns None if not set.
    """
    if not isinstance(profile, dict) or key not in profile:
        return None
    v = profile.get(key)
    if isinstance(v, bool):
        return v
    if isinstance(v, int):
        return bool(v)
    if isinstance(v, str):
        s = v.strip().lower()
        if s in ("1", "true", "yes", "y", "on"):
            return True
        if s in ("0", "false", "no", "n", "off"):
            return False
    return None

