def load_domain_kb(job_function: str) -> dict:
    """Load domain knowledge with cache and a generic fallback."""
    global _domain_kb_cache
    if job_function in _domain_kb_cache:
        return _domain_kb_cache[job_function]

    filename = "generic"
    filepath = resource_path("domain_kb/generic.json")
    try:
        if filepath.exists():
            with open(filepath, "r", encoding="utf-8") as f:
                kb = json.load(f)
        else:
            raise FileNotFoundError(str(filepath))
        _domain_kb_cache[job_function] = kb
        print(f"[Domain KB] loaded: {filename}")
        return kb
    except Exception as e:
        print(f"[Domain KB] load failed ({filepath}): {e}")
        fallback_kb = {
            "domain": "generic",
            "terms": ["progress", "plan", "execution", "quality", "metrics"],
            "deliverables": ["report", "plan", "status sheet"],
            "metrics": ["completion", "quality", "accuracy", "efficiency"],
            "example_facts": [
                "Project duration is two months and completion is 40 percent.",
                "Budget is 500k and 320k has been used.",
                "Team size is five and pass rate is 95 percent.",
            ],
        }
        _domain_kb_cache[job_function] = fallback_kb
        return fallback_kb

        if seg and len(seg) > 2:  # 闂傚倸鍊搁崐椋庣矆娓氣偓楠炴牠顢曚綅閸ヮ剦鏁冮柨鏇楀亾闁汇倗鍋撶换娑㈠箣閻愨晜锛堝┑鐐叉▕娴滄繈寮插┑瀣厱閻忕偟鍋撻惃鎴炪亜閺傛寧鍤囨慨濠冩そ濡啫鈽夊顒夋毇婵犵妲呴崑鍛淬€冮崼婵冩瀻闁靛繈鍊栭崐閿嬬箾閿濆骸鍘哥紒銊ヮ煼濡懘顢曢姀鈥愁槱闂佸湱顭堥…鐤＂闂佺粯顭囩划顖炴偂閺囩喓绠鹃柛鈩兠慨鍥煕濠靛洦銇濋柡灞糕偓宕囨殕閻庯綆鍓涜ⅵ濠电姷顣介崜婵嬪箖閸屾稐绻嗛柣鎴ｆ鍞銈嗘瀹曠數澹曠紒妯肩瘈闁汇垽娼цⅴ闂佺懓鍢查崯鏉戠暦閻旂⒈鏁囬柣鎰ㄦ櫅閹懘姊?
            facts.append({
                "fact_id": f"F{idx+1}",
                "content": seg,
                "mentioned": False,
                "mention_count": 0
            })
    
    return facts


