def write_ledger_debug(dialogue_id: str, ledger_data: dict):
    """闂傚倸鍊搁崐鎼佸磹妞嬪海鐭嗗〒姘ｅ亾妤犵偛顦甸弫鎾绘偐閼碱剦妲烽梻浣告惈缁嬩線宕㈡禒瀣；闁跨喓濮甸悡蹇擃熆鐠虹儤顥炴繛鍛嚇閺?ledger_debug.json"""
    os.makedirs("reports", exist_ok=True)
    
    data = {
        "dialogue_id": dialogue_id,
        "timestamp": datetime.now().isoformat(),
        **ledger_data
    }
    
    output_path = f"reports/ledger_{dialogue_id}.json"
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    
    return output_path

def write_facts_debug(dialogue_id: str, facts_data: dict):
    """闂傚倸鍊搁崐鎼佸磹妞嬪海鐭嗗〒姘ｅ亾妤犵偛顦甸弫鎾绘偐閼碱剦妲烽梻浣告惈缁嬩線宕㈡禒瀣；闁跨喓濮甸悡蹇擃熆鐠虹儤顥炴繛鍛嚇閺?facts_debug.json"""
    os.makedirs("reports", exist_ok=True)
    
    data = {
        "dialogue_id": dialogue_id,
        "timestamp": datetime.now().isoformat(),
        **facts_data
    }
    
    output_path = f"reports/facts_{dialogue_id}.json"
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    
    return output_path


